import React, { useState, useEffect, useRef } from 'react';
import Spinner from './Spinner';
import Model from './Model'
import './App.css';

// Function to load JSON files
async function loadJSON(path) {
  const response = await fetch(path);
  const data = await response.json();
  return data;
}

// Load indices and aggregate them
async function loadData() {
  const root = 'data';
  let out = {}; // everything goes here
  out._lookup = {}; // useful lookup to go from pretty names to urls
  
  // load index, properties and variables
  for (const n of ['index', 'properties', 'variables']) {
    const data = await loadJSON(`${root}/${n}.json`);
    for (const [k, v] of Object.entries(data)) {
      v.attrName = k; // store name for easy lookup
      v.url = `${n}/${k}`; // also store "url" for easy lookup
      out._lookup[v.name] = v.url; // and a lookup that allows us to go from pretty names to urls
      out[`${n}/${k}`] = v;
    }
  }
  
// Load base geometry
const geom = await loadJSON(`${root}/geom/europe_hexagons_with_nuts.geojson`); // TODO; abstract this into some form of ini file? 
out._geometry = geom; // all geometry data
out._gidx = geom.features.map((feature) => feature.properties.index); // list of all geometry indices

// Join spatial data with geometry for plotting
out._featureNames = new Set(); // store list of spatial feature names
for (const [k, v] of Object.entries(out)) {
  if (k.startsWith('index')) { // only look at spatial objects
    // Load the spatial property data
    const data = await loadJSON(`${root}/${v.data}`);
    
    out._geometry.features = out._geometry.features.map((feature) => {
      let attr = null; // Initialize the attribute as null

      // Loop through all keys in feature.properties
      for (const propKey in feature.properties) {
        
        const index = feature.properties[propKey]; // get current property key's value

        attr = data.attr[index]; // try to get value associated with this key in data.attr

        if (attr !== undefined) { // Check if a valid value is found
          feature.properties[k] = attr; // store it for plotting
          break; // Exit the loop as soon as a matching key is found
        }
      }

      if (!v.hidden) {
        out._featureNames.add(v.name); // build list of features for plotting later
      }

      return feature;
    });
  }
}


  // Populate default values for "variables"
  out._variableNames = {}; // list of variable names, by group
  out._variableDefaults = {}
  for (const [k, v] of Object.entries(out)) {
    if (k.startsWith('variables')) {
      // add variable name to relevant group
      if (!(out._variableNames[v.group])){out._variableNames[v.group]=new Set([])}
      out._variableNames[v.group].add( v.name );

      // sort out default value
      if (v.values){ // categorical
        out._variableDefaults[ k ] = v.values[ v.default ];
        v.value = 100*v.values[ v.default ];
      } else {  // slider / numerical
        out._variableDefaults[ k ] = v.default;
        v.value = 100*v.default;
      }
    }
  }
  
  // lastly, load our effect graph
  out._graph = await loadJSON(`${root}/graph.json`);
  out._propertyNames = new Set([]); // unique property names for visualisation
  out._graph.ebunch.forEach( (el) => {
    // N.B. we intentionally don't add start nodes to property names,
    // as this way the root node is ignored.
    if (out[el[1]]){
      const v = out[el[1]];
      if (!(v.hidden)){
        out._propertyNames.add( v.name );
      } 
    } else {
      console.log(`Warning - no node called ${el[1]} exists in properties.json`);
    }
  })
  console.log(out);
  return out;
}

function App() {
  // handle data IO
  // N.B. setData should only be called once [ once the fetching is finished ]
  // child components are not allowed to mutate this, as it casuses a mess!

  const [data, setData] = useState(null); // this will hold all our datasets
  useEffect(() => {
    if (!data) {
      loadData().then((d)=>{
        setData(d);
      });
    } else{
      //console.log("Data already loaded.");
    }
  }, [data]);

  if (data == null){ // still loading -- show spinner
    return (
      <div className="App">
        <div>
          <header>
            <h1 style={{ fontFamily: 'Helvetica', fontWeight: 'bold' }}>Shared Value Mapper</h1>
          </header>
          <Spinner />
          <p><i>Please wait a moment while we fetch some data... </i></p>
        </div>
      </div>
    )
  } else if (true) { // everything loaded -- return app
    return (
      <div className="App">
        <Model data={data}/>
        <footer>
          <p><a href="https://vectorproject.eu/">https://vectorproject.eu/</a></p>
        </footer>
      </div>
    );
  } else {
    return (<p>Done</p>);
  }
}

export default App;
