import React, { useEffect, useRef } from "react";
import ReactD3Library from "react-d3-library";
import * as d3 from "d3";

function ImpactGraph({ impactPaths, data }) {
  const d3Container = useRef();

  const createGraph = () => {
    const width = window.innerWidth * 0.95;
    const height = 600;

    // Prepare data
    const paths = [...impactPaths.positive, ...impactPaths.negative];
    const nodesSet = new Set();
    const links = [];

    paths.forEach((item) => {
      item.path.forEach(([source, target, weight]) => {
        nodesSet.add(source);
        nodesSet.add(target);
        links.push({
          source,
          target,
          weight,
          color: weight < 0 ? "red" : "green",
        });
      });
    });

    const nodes = Array.from(nodesSet).map((id) => ({
      id,
      fx: id === "properties/Mining" ? 50 : id === "properties/SharedValue" ? width - 100 : null,
      fy: id === "properties/Mining" || id === "properties/SharedValue" ? height / 2 : null,
    }));

      // Scale for line width
      const lineWidthScale = d3
        .scaleLinear()
        .domain(d3.extent(links.map((link) => Math.abs(link.weight)))) // Min and max absolute weight
        .range([1, 5]); // Line width range
      
    // Create SVG
    d3.select(d3Container.current).selectAll("*").remove(); // clear previous graphs
    const svg = d3
      .select(d3Container.current)
      .append("svg")
      .attr("width", width)
      .attr("height", height)
      .style("border", "1px solid black");

    // Add title
    svg
    .append("text")
    .attr("x", 20)
    .attr("y", 30)
    .attr("font-size", "20px")
    .attr("font-weight", "bold")
    .attr("fill", "black")
    .text("Impact graph and edge tendencies");

    // Define arrow markers
    // Define arrow markers for each color
    const markerContainer = svg.append("defs");
    links.forEach((link) => {
      markerContainer
        .append("marker")
        .attr("id", `arrowhead-${link.color}`)
        .attr("viewBox", "0 -5 10 10")
        .attr("refX", 10)
        .attr("refY", 0)
        .attr("markerWidth", 6)
        .attr("markerHeight", 6)
        .attr("orient", "auto")
        .append("path")
        .attr("d", "M0,-5L10,0L0,5")
        .attr("fill", link.color);
    });

    // Create simulation
    const simulation = d3
      .forceSimulation(nodes)
      .force(
        "link",
        d3.forceLink(links).id((d) => d.id).distance(10).strength(0.1)
      )
      //.force("charge", d3.forceManyBody().strength(-300)) // repel nodes along edges
      .force("collide", d3.forceCollide(60)) // prevent nodes from overlapping
      //.force("center", d3.forceCenter(width / 2, height / 2))
      .force("radial", d3.forceRadial(height / 2, width / 2, height / 2).strength(0.4)) // Radial repulsion from center
      .on("tick", ticked);

    // Draw links
    const link = svg
      .selectAll(".link")
      .data(links)
      .enter()
      .append("line")
      .attr("class", "link")
      .attr("stroke-width", (d) => lineWidthScale(Math.abs(d.weight)))
      .attr("stroke", (d) => d.color)
      .attr("marker-end", (d) => `url(#arrowhead-${d.color})`);

    // Add edge labels
    const linkLabels = svg
      .selectAll(".link-label")
      .data(links)
      .enter()
      .append("text")
      .attr("class", "link-label")
      .attr("font-size", "14px")
      .attr("fill", "black")
      .attr("stroke", "white") // Add white stroke
      .attr("stroke-width", 5) // Thickness of the stroke
      .attr("paint-order", "stroke") // Ensure stroke renders below text fill
      .text((d) => d.weight.toFixed(2));

    // Draw nodes
    const node = svg
      .selectAll(".node")
      .data(nodes)
      .enter()
      .append("circle")
      .attr("class", "node")
      .attr("r", 8)
      .attr("fill", "blue");

    // Add node labels
    const labels = svg
      .selectAll(".label")
      .data(nodes)
      .enter()
      .append("text")
      .attr("class", "label")
      .attr("font-size", "12px")
      .attr("font-weight", "bold") // Make labels bold
      .attr("fill", "black")
      .attr("stroke", "white") // Add white stroke
      .attr("stroke-width", 5) // Thickness of the stroke
      .attr("paint-order", "stroke") // Ensure stroke renders below text fill
      .text((d) => data[d.id].name);

    // Update positions on simulation tick
    function ticked() {
      link
        .attr("x1", (d) => d.source.x)
        .attr("y1", (d) => d.source.y)
        .attr("x2", (d) => d.target.x)
        .attr("y2", (d) => d.target.y);

      node.attr("cx", (d) => d.x).attr("cy", (d) => d.y);

      labels
        .attr("x", (d) => d.x + 10)
        .attr("y", (d) => d.y + 3);

      linkLabels
        .attr("x", (d) => (d.source.x + d.target.x) / 2)
        .attr("y", (d) => (d.source.y + d.target.y) / 2);
    }

    // Drag behavior
    const drag = d3
      .drag()
      .on("start", (event, d) => {
        if (!event.active) simulation.alphaTarget(0.3).restart();
        d.fx = d.x;
        d.fy = d.y;
      })
      .on("drag", (event, d) => {
        d.fx = event.x;
        d.fy = event.y;
      })
      .on("end", (event, d) => {
        if (!event.active) simulation.alphaTarget(0);
        if (d.id !== "properties/Mining" && d.id !== "properties/SharedValue") {
          d.fx = null;
          d.fy = null;
        }
      });

    node.call(drag);
  };

  useEffect(() => {
    createGraph();
  }, [impactPaths]);

  return <div ref={d3Container}></div>;
}

export default ImpactGraph;
