import { useRef } from 'react';
import { useMap } from 'react-leaflet';
import L from 'leaflet';

function Sidebar({ styleProps, change_cmap, 
                   attributes, change_attr, 
                   selectedAttribute, variables, 
                   update_variables, data}) {
    

    // build variables selector
    const var_items = [ ];
    Object.entries(variables).map(([key, value]) => {
        var_items.push(<div><p>{key}</p></div>)
        value.forEach( (n) => {
            const v = data[ data._lookup[n] ];
            if (v.values){ // categorical
                var_items.push(<div>
                    <select id={n} name={n} key={n} style={{width:"10em"}} defaultValue={v.value}>
                        {Object.entries(v.values).map(([attr, attrval]) => {
                                return ( <option value={attrval*100} key={attr}>{attr}</option> );
                            })}
                    </select>
                    <label key={n+"_label"} htmlFor={n} style={{marginLeft:"1em"}}>{v.name}</label>
                </div> );

            } else {  // slider / numerical
                var_items.push(<div>
                    <input type="range" id={n} name={n} key={n} min={100*v.range[0]} max={100*v.range[1]} style={{width:"10em"}}/>
                    <label key={n+"_label"} htmlFor={n} style={{marginLeft:"1em"}}>{v.name}</label>
                </div>
                );
            }
        });
    });

    // callback for "apply" button
    const apply = (evt) => {
        const out = {};
        Object.entries(variables).map(([key, value]) => {
            value.forEach( (n) => { 
                out[ data._lookup[n] ] = parseFloat(document.getElementById(n).value) / 100;
            } );
         } );
        update_variables(out); // pass on upwards
    }
    var_items.push( 
        <button id="updateData" type="button" style={{width:"100%"}} onClick={apply}>Apply</button>
    );
    var_items.push( <hr/> );

    // build attributes selector
    const attr_items= [ ];
    Object.entries(attributes).map(([key, value]) => {
        value.forEach( (v) => { 
            attr_items.push( <option key={v} value={v}>{v}</option> );
            });
            attr_items.push( <hr key={key}/>);
    });
    const attr = (
        <select id="attribute-select" 
                style={{width:"10em"}} 
                value={selectedAttribute}
                onChange={change_attr}>
            {attr_items}
        </select> );
    
    // build colormap selector
    const cmap = (
        <select id="property-select" 
                style={{width:"10em"}} 
                value={styleProps.selectedScheme}
                onChange={change_cmap}>
        {Object.entries(styleProps.schemes).map(([key, value]) => {
            return( <option key={key} value={key}>{key}</option>); })}
        </select>);

    // build color legend item
    const legend = [];
    const s = 2; // step for legend bins
    for (let i = 0; i < styleProps.breaks.length - 1; i+=s) {
      const from = styleProps.breaks[i];
      const to = styleProps.breaks[i + s];
      const color = styleProps.color_func( (from + to) / 2).hex();
      legend.push(
        <span key={from}>
            <br/><i key={color} style={{background:color, padding: '5px 25px'}}> 
            </i><span key={to} style={{padding: '0px 25px'}}>{from.toFixed(2)} &rarr; {to.toFixed(2)}</span>
        </span>
      );
    }

    return (
        <div
          style={{
            position: 'absolute',
            textAlign: 'left',
            bottom: '10px',
            left: '10px',
            padding: '5px 10px',
            backgroundColor: 'rgba(255, 255, 255, 0.8)',
            borderRadius: '4px',
            boxShadow: '0 2px 5px rgba(0, 0, 0, 0.3)',
            fontSize: '14px',
            fontWeight: 'bold',
            zIndex: 1000, // Ensures overlay is above the map
          }}
        >
        <div>
          {var_items}
        </div>

        <b>Attribute</b>
        <div>
            {attr}
        </div>

        <b>Colormap</b>
        <div>
            {cmap}
         <div>
            <b>Legend</b>
            {legend}
        </div>
        </div>
      </div>
    );
}

export default Sidebar;
